// // This module implements a combinational circuit that outputs 1 if A > 5 or B != 2, and outputs 1 if C == 0 or D != 1 or E != 1
module combinational_circuit(
    input [3:0] A,
    input [1:0] B,
    input C,
    input D,
    input E,
    output X
);

    assign X = ((A <= 5) && (B == 2)) ? 1 :
               ((C == 1) && (D == 0) && (E == 1)) ? 1 : 0;

endmodule
